import { NextRequest, NextResponse } from 'next/server'
import { regenerateContentWithFeedback } from '@/lib/agent/orchestrator'

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const body = await request.json()
    const { feedback } = body

    if (!feedback || typeof feedback !== 'string') {
      return NextResponse.json({ error: 'Feedback is required' }, { status: 400 })
    }

    const updated = await regenerateContentWithFeedback(id, feedback)

    return NextResponse.json({ success: true, item: updated })
  } catch (error: any) {
    console.error('Regenerate failed:', error)
    return NextResponse.json(
      { error: error.message || 'Failed to regenerate content' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const body = await request.json().catch(() => ({}))
    const { feedback } = body

    const updated = await prisma.contentItem.update({
      where: { id },
      data: {
        status: 'REJECTED',
        humanFeedback: feedback || null,
      },
    })

    await prisma.activityLog.create({
      data: {
        type: 'CONTENT_REJECTED',
        summary: `Rejected ${updated.platform} content`,
        details: { 
          contentItemId: id, 
          platform: updated.platform,
          feedback: feedback || null 
        },
        contentItemId: id,
      },
    })

    return NextResponse.json({ success: true, item: updated })
  } catch (error) {
    console.error('Reject failed:', error)
    return NextResponse.json({ error: 'Failed to reject item' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params
    const body = await request.json()

    const { body: newBody, title, agentReasoning } = body

    const updated = await prisma.contentItem.update({
      where: { id },
      data: {
        ...(newBody && { body: newBody }),
        ...(title && { title }),
        ...(agentReasoning && { agentReasoning }),
      },
    })

    await prisma.activityLog.create({
      data: {
        type: 'CONTENT_REGENERATED', // reuse for now, or we can add EDITED later
        summary: `Edited ${updated.platform} content`,
        details: { contentItemId: id, platform: updated.platform },
        contentItemId: id,
      },
    })

    return NextResponse.json({ success: true, item: updated })
  } catch (error) {
    console.error('Update failed:', error)
    return NextResponse.json({ error: 'Failed to update item' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET() {
  try {
    const items = await prisma.contentItem.findMany({
      where: { status: 'PENDING_APPROVAL' },
      orderBy: { createdAt: 'desc' },
    })

    return NextResponse.json({ items })
  } catch (error) {
    console.error('Failed to fetch pending content:', error)
    return NextResponse.json({ error: 'Failed to load pending items' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const status = searchParams.get('status') as any
  const limit = parseInt(searchParams.get('limit') || '50', 10)
  const formats = searchParams.getAll('format')

  try {
    const where: any = {}
    if (status) {
      where.status = status
    }
    if (formats.length > 0) {
      where.format = { in: formats }
    }

    const items = await prisma.contentItem.findMany({
      where,
      orderBy: { createdAt: 'desc' },
      take: limit,
    })

    return NextResponse.json({ items })
  } catch (error) {
    console.error('Failed to fetch content items:', error)
    return NextResponse.json({ error: 'Failed to load items' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET() {
  try {
    const [recentLogs, pendingCount, latestRun] = await Promise.all([
      prisma.activityLog.findMany({
        orderBy: { timestamp: 'desc' },
        take: 12,
      }),
      prisma.contentItem.count({
        where: { status: 'PENDING_APPROVAL' },
      }),
      prisma.agentRun.findFirst({
        orderBy: { startedAt: 'desc' },
      }),
    ])

    // Check if brand exists
    const brand = await prisma.brandContext.findFirst()

    return NextResponse.json({
      recentLogs,
      pendingCount,
      latestRun: latestRun ? {
        ...latestRun,
        // Include summary for display
        summary: latestRun.summary,
      } : null,
      hasBrand: !!brand,
    })
  } catch (error) {
    console.error('Dashboard activity error:', error)
    // Return safe fallback
    return NextResponse.json({
      recentLogs: [],
      pendingCount: 0,
      latestRun: null,
      hasBrand: false,
    })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { prisma } from '@/lib/db/prisma'
import { brandContextToBusinessProfile } from '@/lib/agent/brand-adapter'
import { recommendTopics } from '@/lib/agent/recommend-topic'
import { AIProviderSchema } from '@/lib/agent/types'
import { getActiveProvider } from '@/lib/settings/api-key'

const RequestSchema = z.object({
  brandContextId: z.string(),
  provider: AIProviderSchema.optional(),
  count: z.number().min(3).max(8).optional(),
})

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = RequestSchema.safeParse(body)
    if (!parsed.success) {
      return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
    }

    const brand = await prisma.brandContext.findUnique({
      where: { id: parsed.data.brandContextId },
    })
    if (!brand) {
      return NextResponse.json({ error: 'Business not found' }, { status: 404 })
    }

    const provider = parsed.data.provider ?? (await getActiveProvider())
    const business = brandContextToBusinessProfile(brand)

    const result = await recommendTopics({
      provider,
      business,
      count: parsed.data.count ?? 5,
    })

    return NextResponse.json(result)
  } catch (error: unknown) {
    console.error('Topic recommendation failed:', error)
    const message = error instanceof Error ? error.message : 'Failed to suggest topics'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'
import { prisma } from '@/lib/db/prisma'
import { brandContextToBusinessProfile } from '@/lib/agent/brand-adapter'
import { regenerateEpisodeSection } from '@/lib/agent/regenerate-episode'
import { AIProviderSchema, ContentEpisodePayloadSchema, SocialPlatformSchema } from '@/lib/agent/types'
import { getActiveProvider } from '@/lib/settings/api-key'

const RequestSchema = z.object({ packageId: z.string(), platform: SocialPlatformSchema, feedback: z.string().min(1), provider: AIProviderSchema.optional() })

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const parsed = RequestSchema.safeParse(body)
    if (!parsed.success) return NextResponse.json({ error: 'Invalid request' }, { status: 400 })
    const pkg = await prisma.contentPackage.findUnique({ where: { id: parsed.data.packageId }, include: { brandContext: true } })
    if (!pkg) return NextResponse.json({ error: 'Package not found' }, { status: 404 })
    const provider = parsed.data.provider ?? (await getActiveProvider())
    const business = brandContextToBusinessProfile(pkg.brandContext)
    const currentPayload = ContentEpisodePayloadSchema.parse({ platforms: pkg.platforms as string[], strategyNote: pkg.strategyNote, agentReasoning: pkg.agentReasoning, content: pkg.content })
    const result = await regenerateEpisodeSection({ provider, business, topic: pkg.topic, platform: parsed.data.platform, currentPayload, feedback: parsed.data.feedback })
    const updated = await prisma.contentPackage.update({ where: { id: pkg.id }, data: { strategyNote: result.payload.strategyNote, agentReasoning: result.payload.agentReasoning, content: result.payload.content } })
    await prisma.activityLog.create({ data: { type: 'CONTENT_REGENERATED', summary: `Regenerated ${parsed.data.platform} content with feedback`, details: { packageId: pkg.id, platform: parsed.data.platform } } })
    return NextResponse.json({ package: { id: updated.id, businessId: updated.brandContextId, topic: updated.topic, provider: updated.provider, platforms: updated.platforms, strategyNote: updated.strategyNote, agentReasoning: updated.agentReasoning, content: updated.content, createdAt: updated.createdAt.toISOString() }, model: result.model, usage: result.usage })
  } catch (error: unknown) {
    console.error('Regenerate failed:', error)
    const message = error instanceof Error ? error.message : 'Regeneration failed'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}
